// Creating an object
const user = {
  name: "Alice",
  age: 28,
  email: "alice@example.com",
  isActive: true
};

// Accessing properties
console.log(user.name);         // "Alice" — dot notation
console.log(user["age"]);       // 28 — bracket notation
console.log(user.phone ?? "N/A"); // "N/A" — nullish coalescing

// Modifying
user.age = 29;                  // update
user.city = "Berlin";           // add new
delete user.email;              // remove

// Checking keys
console.log("name" in user);    // true

// Iterating
for (const [key, value] of Object.entries(user)) {
  console.log(`${key}: ${value}`);
}

// Destructuring — extract to variables
const { name, age } = user;
console.log(name, age);  // Alice 29

